const fs = require('fs');

const app = express();

app.get('/', (req, res) => {
  const url = 'http://pornpics.com/tags/{something}';
  request.get(url, (error, response, body) => {
    if (error) {
      res.status(500).send('Error:'+ error);
      } else {
        const images = body.split('images-container\\nimages-');
        images.forEach((image) => {
          const filename = image.split('-')[2];
          const path = `${__dirname}/images/${filename}`;

          fs.writeFile(path, image, (error) => {
            if (error) {
              res.status(500).send('Error:'+ error);
            } else {
              res.send('Image saved to'+ filename);
            }
          });
        });
      }
    }
  });
});

app.listen(3000, () => {
  console.log('Server listening on port 3000');
});
